function solve(nums) {
    const n = nums.length;
    const ans = new Array(2 * n);

    // First n elements are the same as nums
    for (let i = 0; i < n; i++) {
        ans[i] = nums[i];
    }

    // Last n elements are the reverse of nums
    // ans[i + n] = nums[n - i - 1] for 0 <= i <= n - 1
    for (let i = 0; i < n; i++) {
        // i ranges from 0 to n-1
        // The index in ans is i + n
        // The corresponding index in nums is n - 1 - i
        ans[i + n] = nums[n - 1 - i];
    }

    return ans;
}
